 1→import React, { useState } from 'react';
 2→import { View, Pressable } from 'react-native';
 3→import { Box, Text, SeparatorHorizontal } from '@semparar/design-system-app';
 4→import type { SDUIComponentProps, SDUIContext } from '../models';
 5→
 6→interface TabItem {
 7→  id: number;
 8→  title: string;
 9→}
10→
11→interface TabBarProps extends SDUIComponentProps {
12→  tabs: TabItem[];
13→  mt?: string;
14→  mb?: string;
15→  ml?: string;
16→}
17→
18→export default function TabBarAdapter({
19→  props,
20→}: {
21→  props: TabBarProps;
22→  context: SDUIContext;
23→}) {
24→  const { tabs = [], ml = 'smaller', mt, mb } = props;
25→  const [activeTab, setActiveTab] = useState(0);
26→
27→  return (
28→    <Box mt={mt} mb={mb}>
29→      <View style={{ flexDirection: 'row', marginLeft: ml === 'smaller' ? 12 : 0, marginBottom: 4 }}>
30→        {tabs.map((tab: TabItem, idx: number) => {
31→          const isActive = idx === activeTab;
32→          return (
33→            <Pressable
34→              key={tab.id ?? idx}
35→              onPress={() => setActiveTab(idx)}
36→              style={{ marginRight: 16, paddingBottom: 8, borderBottomWidth: isActive ? 2 : 0, borderBottomColor: '#E91E63' }}
37→            >
38→              <Text
39→                type={isActive ? 'subtitleXXL' : 'paragraphMD'}
40→                color={isActive ? 'INTENSE_COLOR_05' : 'INTENSE_COLOR_03'}
41→              >
42→                {tab.title}
43→              </Text>
44→            </Pressable>
45→          );
46→        })}
47→      </View>
48→      <SeparatorHorizontal width="100%" height={1} borderColor="BRAND_COMPLEMENT_02" />
49→    </Box>
50→  );
51→}
