import React, { useState } from 'react';
import { View, Pressable } from 'react-native';
import { Box, Text, SeparatorHorizontal } from '@semparar/design-system-app';
import type { SDUIComponentProps, SDUIContext } from '../models';

interface TabItem {
  id: number;
  title: string;
}

interface TabBarProps extends SDUIComponentProps {
  tabs: TabItem[];
  mt?: string;
  mb?: string;
  ml?: string;
}

export default function TabBarAdapter({
  props,
}: {
  props: TabBarProps;
  context: SDUIContext;
}) {
  const { tabs = [], ml = 'smaller', mt, mb } = props;
  const [activeTab, setActiveTab] = useState(0);

  return (
    <Box mt={mt} mb={mb}>
      <View style={{ flexDirection: 'row', marginLeft: ml === 'smaller' ? 12 : 0, marginBottom: 4 }}>
        {tabs.map((tab: TabItem, idx: number) => {
          const isActive = idx === activeTab;
          return (
            <Pressable
              key={tab.id ?? idx}
              onPress={() => setActiveTab(idx)}
              style={{ marginRight: 16, paddingBottom: 8, borderBottomWidth: isActive ? 2 : 0, borderBottomColor: '#E91E63' }}
            >
              <Text
                type={isActive ? 'subtitleXXL' : 'paragraphMD'}
                color={isActive ? 'INTENSE_COLOR_05' : 'INTENSE_COLOR_03'}
              >
                {tab.title}
              </Text>
            </Pressable>
          );
        })}
      </View>
      <SeparatorHorizontal width="100%" height={1} borderColor="BRAND_COMPLEMENT_02" />
    </Box>
  );
}

import React, { useState } from 'react';
import { ScrollView, View, Pressable } from 'react-native';
import {
  Text,
  Box,
  CardPoints,
  Header,
  Icon,
  SearchUsed,
  SeparatorHorizontal,
} from '@semparar/design-system-app';
import type { Meta, StoryObj } from 'storybook/internal/types';
import type { SDUIScreen } from '../services/sdui/models';
import ScreenRenderer from '../services/sdui/renderer/ScreenRenderer';
import { registerAllAdapters } from '../services/sdui/adapters';
import { useSDUIJsonEditor } from '../../.storybook/addons/json-editor';
import {
  extractHistoryLoaded,
  extractHistoryEmpty,
} from '../services/sdui/mocks';

registerAllAdapters();

type ViewState = 'loaded' | 'empty';

const SCREENS: Record<ViewState, SDUIScreen> = {
  loaded: extractHistoryLoaded,
  empty: extractHistoryEmpty,
};

function ViewToggle({
  selected,
  onSelect,
}: {
  selected: ViewState;
  onSelect: (v: ViewState) => void;
}) {
  const labels: Record<ViewState, string> = {
    loaded: 'Loaded (8)',
    empty: 'Empty',
  };

  return (
    <View style={{ flexDirection: 'row', gap: 8, marginBottom: 16 }}>
      {(['loaded', 'empty'] as const).map(v => (
        <Pressable
          key={v}
          onPress={() => onSelect(v)}
          style={{
            paddingHorizontal: 16,
            paddingVertical: 8,
            borderRadius: 20,
            backgroundColor: selected === v ? '#6B2FBE' : '#E8E0F0',
          }}
        >
          <Text
            type="paragraphMDM"
            color={selected === v ? 'LIGHT_BASE_01' : 'INTENSE_COLOR_05'}
          >
            {labels[v]}
          </Text>
        </Pressable>
      ))}
    </View>
  );
}

function ExtractDemo() {
  const [view, setView] = useState<ViewState>('loaded');
  const screen = useSDUIJsonEditor(SCREENS[view]);

  return (
    <ScrollView style={{ flex: 1 }}>
      <View style={{ padding: 24, maxWidth: 420 }}>
        <Text type="headingMDL" mb="nano">
          SDUI: Extrato
        </Text>
        <Text type="bodyMD" mb="smaller" color="INTENSE_COLOR_03">
          Renders the transaction history from JSON via SDUI engine. Transactions
          use context interpolation — edit the JSON to change data dynamically.
        </Text>

        <ViewToggle selected={view} onSelect={setView} />

        <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm">
          <ScreenRenderer screen={screen} />
        </Box>
      </View>
    </ScrollView>
  );
}

const REAL_TRANSACTIONS = (extractHistoryLoaded.context.transactions as Record<string, string>[]).map(t => ({
  icon: String(t.icon),
  title: String(t.title),
  value: String(t.value),
  valueColor: String(t.valueColor),
  typeLabel: String(t.typeLabel),
  showIcon: t.showIcon !== false,
}));

const DATE_GROUPS = [
  { label: '20 de fevereiro', items: REAL_TRANSACTIONS.slice(0, 2) },
  { label: '18 de fevereiro', items: REAL_TRANSACTIONS.slice(2, 4) },
  { label: '15 de fevereiro', items: REAL_TRANSACTIONS.slice(4, 5) },
  { label: '12 de fevereiro', items: REAL_TRANSACTIONS.slice(5, 7) },
  { label: '10 de fevereiro', items: REAL_TRANSACTIONS.slice(7, 8) },
];

const VALUE_COLOR_MAP: Record<string, string> = {
  green: 'ACCEPT_COLOR_01',
  red: 'DENY_COLOR_01',
  gray: 'INTENSE_COLOR_03',
  orange: 'ALERT_COLOR_01',
};

function RealScreenPreview() {
  return (
    <Box bgColor="BRAND_COMPLEMENT_03" flex={1}>
      <Header
        title="Extrato"
        iconLeft="icon-back"
        hideLeftIcon={false}
        onBack={() => {}}
      />
      <Box ml="smaller" mr="smaller" mt="smaller" mb="xxxs">
        <CardPoints
          icon="icon-benefits"
          iconInfo="icon-help"
          title="Pontos disponíveis"
          valuePoints="15.320"
          hideBottom
          isLoading={false}
          onPressIconInfo={() => {}}
        />
        <Text type="paragraphXXXL" mb="xxxxs" mt="xxs" color="INTENSE_COLOR_05">
          Lançamentos
        </Text>
        <SeparatorHorizontal
          borderWidth="smaller"
          borderColor="BRAND_COMPLEMENT_02"
          height={1}
          mb="xxxxs"
          width="100%"
        />
        <SearchUsed
          placeholder="Buscar por pontos, tipos de compra etc"
          onChangeText={() => {}}
          value=""
          showIcon={false}
          firstIcon={undefined}
          onPressIn={() => {}}
          numberIcon={undefined}
          secondIcon="icon-filter-settings"
          secondOnPress={() => {}}
          showFilter
        />
      </Box>
      <View style={{ flexDirection: 'row', marginLeft: 12, marginBottom: 4 }}>
        <View style={{ marginRight: 16, paddingBottom: 8, borderBottomWidth: 2, borderBottomColor: '#E91E63' }}>
          <Text type="subtitleXXL" color="INTENSE_COLOR_05">Todos</Text>
        </View>
        <View style={{ paddingBottom: 8 }}>
          <Text type="paragraphMD" color="INTENSE_COLOR_03">A expirar</Text>
        </View>
      </View>
      <SeparatorHorizontal width="100%" height={1} borderColor="BRAND_COMPLEMENT_02" />
      {DATE_GROUPS.map(group => (
        <React.Fragment key={group.label}>
          <Box mt="xs" mb="xxxs" ml="smaller">
            <Text type="captionMD" color="INTENSE_COLOR_03">{group.label}</Text>
          </Box>
          {group.items.map((item, idx) => (
            <Box
              key={idx}
              direction
              pd="squishSmall"
              mb="xxxs"
              align="center"
              bgColor="LIGHT_BASE_01"
              br="sm"
              ml="smaller"
              mr="smaller"
              style={{ minHeight: 56 }}
            >
              {item.showIcon && (
                <Box
                  width={36}
                  height={36}
                  align="center"
                  justify="center"
                  bgColor="BRAND_COMPLEMENT_02"
                  mr="xxxs"
                  style={{ borderRadius: 18 }}
                >
                  <Icon name={item.icon} size="sm" color="INTENSE_COLOR_05" />
                </Box>
              )}
              <Box flex={1}>
                <Text type="paragraphMDM" numberOfLines={1}>{item.title}</Text>
                <Text type="captionSM" color="INTENSE_COLOR_03">{item.typeLabel}</Text>
              </Box>
              <Box align="flex-end">
                <Text type="paragraphMDM" color={VALUE_COLOR_MAP[item.valueColor] ?? item.valueColor}>
                  {item.value}
                </Text>
              </Box>
            </Box>
          ))}
        </React.Fragment>
      ))}
    </Box>
  );
}

function SideBySideComparison() {
  const screen = useSDUIJsonEditor(extractHistoryLoaded);

  return (
    <ScrollView style={{ flex: 1 }}>
      <View style={{ padding: 24 }}>
        <Text type="headingMDL" mb="nano">
          Side-by-Side: Real Screen vs SDUI
        </Text>
        <Text type="bodyMD" mb="smaller" color="INTENSE_COLOR_03">
          Left: traditional React components with hardcoded data. Right: same
          visual result rendered entirely from JSON via the SDUI engine.
        </Text>

        <View style={{ flexDirection: 'row', gap: 24 }}>
          <View style={{ flex: 1, maxWidth: 420 }}>
            <Text type="subtitleXXL" mb="nano" align="center">
              Real Screen (SP_0004.1)
            </Text>
            <Box br="sm" style={{ overflow: 'hidden' }}>
              <RealScreenPreview />
            </Box>
          </View>

          <View style={{ flex: 1, maxWidth: 420 }}>
            <Text type="subtitleXXL" mb="nano" align="center">
              SDUI from JSON
            </Text>
            <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm">
              <ScreenRenderer screen={screen} />
            </Box>
          </View>
        </View>

        <SeparatorHorizontal mv="xs" />

        <Box pd="innerSmall" bgColor="BRAND_COMPLEMENT_02" br="sm">
          <Text type="paragraphMDM" mb="xxxs">
            Key difference
          </Text>
          <Text type="bodyMD" color="INTENSE_COLOR_03">
            The left column requires code changes to update transaction data. The
            right column renders from JSON — the backend can add transactions,
            change dates, or update points values without any frontend deploy.
          </Text>
        </Box>
      </View>
    </ScrollView>
  );
}

const meta: Meta = {
  title: 'SDUI/Extract History',
  component: ExtractDemo,
};

export default meta;

type Story = StoryObj<typeof meta>;

export const Demo: Story = {
  render: () => <ExtractDemo />,
};

export const Comparison: Story = {
  name: 'Side-by-Side Comparison',
  render: () => <SideBySideComparison />,
};
